module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output mul_en_out,
    output [15:0] mul_out
);
    // ADD CODE BELOW
    // Input control
    reg mul_en_out_reg[1:0]; // Register to store the value of mul_en_in for the next clock cycle
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) // Active-low reset signal. Defined as 0 for chip reset and 1 for reset signal inactive
            mul_en_out_reg[0] <= 1'b0;
        else
            mul_en_out_reg[0] <= mul_en_in; // Assign the value of mul_en_in to the register on the positive edge of the clock signal
    end
    assign mul_en_out = mul_en_out_reg[1]; // Output enable signal indicating if the multiplication operation is enabled
    // Input registers
    reg [7:0] mul_a_reg[1:0]; // Register to store the value of mul_a for the next clock cycle
    reg [7:0] mul_b_reg[1:0]; // Register to store the value of mul_b for the next clock cycle
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            mul_a_reg[0] <= 8'b0;
        else if (mul_en_out_reg[0])
            mul_a_reg[0] <= mul_a; // Assign the value of mul_a to the register on the positive edge of the clock signal when the input enable signal is active
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            mul_b_reg[0] <= 8'b0;
        else if (mul_en_out_reg[0])
            mul_b_reg[0] <= mul_b; // Assign the value of mul_b to the register on the positive edge of the clock signal when the input enable signal is active
    end
    // Partial product generation
    wire [15:0] temp[7:0]; // Declare an array of wires to store the value of the partial products
    assign temp[0] = mul_a_reg[0] & {8{mul_b_reg[0][0]}}; // Generate the first partial product by performing bitwise operations between the multiplicand and the individual bits of the multiplier
    assign temp[1] = mul_a_reg[0] & {8{mul_b_reg[0][1]}}; // Generate the second partial product by performing bitwise operations between the multiplicand and the individual bits of the multiplier
    assign temp[2] = mul_a_reg[0] & {8{mul_b_reg[0][2]}}; // Generate the third partial product by performing bitwise operations between the multiplicand and the individual bits of the multiplier
    assign temp[3] = mul_a_reg[0] & {8{mul_b_reg[0][3]}}; // Generate the fourth partial product by performing bitwise operations between the multiplicand and the individual bits of the multiplier
    assign temp[4] = mul_a_reg[0] & {8{mul_b_reg[0][4]}}; // Generate the fifth partial product by performing bitwise operations between the multiplicand and the individual bits of the multiplier
    assign temp[5] = mul_a_reg[0] & {8{mul_b_reg[0][5]}}; // Generate the sixth partial product by performing bitwise operations between the multiplicand and the individual bits of the multiplier
    assign temp[6] = mul_a_reg[0] & {8{mul_b_reg[0][6]}}; // Generate the seventh partial product by performing bitwise operations between the multiplicand and the individual bits of the multiplier
    assign temp[7] = mul_a_reg[0] & {8{mul_b_reg[0][7]}}; // Generate the eighth partial product by performing bitwise operations between the multiplicand and the individual bits of the multiplier
    // ADD CODE BELOW
    // Partial sum calculation
    reg [15:0] sum[7:0]; // Register to store the value of the partial sum for the next clock cycle
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sum[0] <= 16'b0;
        else
            sum[0] <= temp[0]; // Assign the value of the first partial product to the register on the positive edge of the clock signal
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sum[1] <= 16'b0;
        else
            sum[1] <= sum[0] + temp[1]; // Assign the accumulated sum of the first two partial products to the register on the positive edge of the clock signal
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sum[2] <= 16'b0;
        else
            sum[2] <= sum[1] + temp[2]; // Assign the accumulated sum of the first three partial products to the register on the positive edge of the clock signal
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sum[3] <= 16'b0;
        else
            sum[3] <= sum[2] + temp[3]; // Assign the accumulated sum of the first four partial products to the register on the positive edge of the clock signal
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sum[4] <= 16'b0;
        else
            sum[4] <= sum[3] + temp[4]; // Assign the accumulated sum of the first five partial products to the register on the positive edge of the clock signal
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sum[5] <= 16'b0;
        else
            sum[5] <= sum[4] + temp[5]; // Assign the accumulated sum of the first six partial products to the register on the positive edge of the clock signal
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sum[6] <= 16'b0;
        else
            sum[6] <= sum[5] + temp[6]; // Assign the accumulated sum of the first seven partial products to the register on the positive edge of the clock signal
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            sum[7] <= 16'b0;
        else
            sum[7] <= sum[6] + temp[7]; // Assign the accumulated sum of all partial products to the register on the positive edge of the clock signal
    end
    // ADD CODE BELOW
    // Final product calculation
    reg [15:0] mul_out_reg; // Register to store the accumulated sum of all partial sums for the next clock cycle
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            mul_out_reg <= 16'b0;
        else
            mul_out_reg <= sum[7]; // Assign the accumulated sum of all partial sums to the register on the positive edge of the clock signal
    end
    assign mul_out = mul_en_out ? mul_out_reg : 16'b0; // Output signal representing the product of the multiplicand and multiplier
    // ADD CODE ABOVE
endmodule
